import{_ as t,o as i,c as r,a2 as s}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Setup & RGPD","description":"","frontmatter":{"title":"Setup & RGPD"},"headers":[],"relativePath":"docs/fr/publishers/co-branded-contest/setup-guide.md","filePath":"docs/fr/publishers/co-branded-contest/setup-guide.md"}'),n={name:"docs/fr/publishers/co-branded-contest/setup-guide.md"};function o(d,e,a,l,p,c){return i(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="guide-de-mise-en-place" tabindex="-1">Guide de mise en place <a class="header-anchor" href="#guide-de-mise-en-place" aria-label="Permalink to &quot;Guide de mise en place&quot;">​</a></h1><p>Les étapes techniques et juridiques pour lancer un jeu concours co-brandé conforme.</p><hr class="my-6"><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">1</div><div><h3 class="mt-0 text-purple-200">Création de la Landing Page (LP)</h3><p>Vous êtes responsable de l&#39;hébergement du jeu pour rassurer votre client.</p><ul><li><strong>URL :</strong> Sur votre domaine (ex: <code>votre-site.com/jeu-concours-marque</code>).</li><li><strong>Design :</strong> Co-brandé (Votre header habituel + l&#39;univers visuel de l&#39;Annonceur).</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#d73a49;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">!</div><div><h3 class="mt-0 text-red-200">Le Formulaire &amp; RGPD (Critique)</h3><p>Pour monétiser la donnée (vendre le lead à l&#39;annonceur), le formulaire doit respecter strictement le RGPD.</p><div style="background:var(--vp-c-bg-elv);border:2px dashed #d73a49;padding:20px;border-radius:8px;margin-top:15px;"><p class="mb-2 fs-4 fw-700 text-grey-dk-000">Mention obligatoire à insérer :</p><div style="display:flex;gap:10px;align-items:center;"><div style="width:20px;height:20px;border:1px solid #999;border-radius:3px;"></div><div style="font-style:italic;">J&#39;accepte de recevoir les offres commerciales du partenaire [Nom de l&#39;Annonceur].</div></div><p class="mt-3 mb-0 fs-2 text-grey-dk-000">⚠️ Cette case ne doit <strong>JAMAIS</strong> être pré-cochée.</p></div><p class="mt-2 text-grey-dk-000"><em>Note : Seuls les participants cochant cette case seront facturés à l&#39;Annonceur. Les autres jouent mais ne sont pas monétisables.</em></p></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">3</div><div><h3 class="mt-0 text-purple-200">Plan d&#39;activation</h3><p>Pour garantir le volume de leads (et donc vos revenus), activez vos leviers puissants :</p><ul><li><strong>📧 Newsletter dédiée :</strong> &quot;Tentez de gagner XXX€ chez [Marque]&quot;.</li><li><strong>🔔 Web Push Notification.</strong></li><li><strong>🖼️ Bannières Home Page.</strong></li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#28a745;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">✓</div><div><h3 class="mt-0 text-green-200">Transfert des données</h3><p>À la clôture du jeu :</p><ol><li>Exportez la liste des participants <strong>avec l&#39;opt-in partenaire</strong> (CSV/Excel).</li><li>Transmettez le fichier de manière sécurisée à l&#39;Annonceur (via getinside).</li></ol><div style="background:#f0fcf4;padding:10px;border-radius:4px;border-left:4px solid #28a745;margin-top:10px;"><strong>Bonne nouvelle :</strong> Une fois le fichier envoyé, votre travail est terminé. L&#39;Annonceur gère l&#39;envoi des emails de consolation et des codes promos. </div></div></div>',7)])])}const m=t(n,[["render",o]]);export{g as __pageData,m as default};
